# USER-LEVEL CHANNEL ENRICHMENT
# в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
# Р”РѕР±Р°РІР»СЏРµС‚ РєР°РЅР°Р»С‹ РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ (Discord, Telegram) Рє agent_caps.
# Р­С‚Рё РєР°РЅР°Р»С‹ С…СЂР°РЅСЏС‚СЃСЏ РЅР° СѓСЂРѕРІРЅРµ users, Р° РЅРµ user_agents,
# РїРѕСЌС‚РѕРјСѓ _parse_agent_integrations() РёС… РЅРµ РІРёРґРёС‚.

def _enrich_caps_with_user_channels(caps: list, user=None) -> list:
    """Р”РѕРїРѕР»РЅСЏРµС‚ СЃРїРёСЃРѕРє РёРЅС‚РµРіСЂР°С†РёР№ Р°РіРµРЅС‚Р° user-level РєР°РЅР°Р»Р°РјРё.
    
    Р”Р»СЏ РґРѕР±Р°РІР»РµРЅРёСЏ РЅРѕРІРѕРіРѕ РєР°РЅР°Р»Р°: РґРѕР±Р°РІРёС‚СЊ РїРѕР»Рµ РІ models.User + СЃС‚СЂРѕРєСѓ РЅРёР¶Рµ.
    """
    if not user:
        return caps
    enriched = set(caps)
    # (Р°С‚СЂРёР±СѓС‚ РјРѕРґРµР»Рё User, label РґР»СЏ РёРЅС‚РµРіСЂР°С†РёРё)
    _USER_CHANNELS = [
        ('discord_webhook', 'Discord (РєР°РЅР°Р» РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ)'),
        ('telegram_channel', 'Telegram-РєР°РЅР°Р» (РєР°РЅР°Р» РїРѕР»СЊР·РѕРІР°С‚РµР»СЏ)'),
    ]
    for attr, label in _USER_CHANNELS:
        if getattr(user, attr, None):
            enriched.add(label)
    return sorted(enriched)


