def _match_best_integration(goal_title: str,
                             has_imap: bool = False, has_github: bool = False, has_rss: bool = False,
                             has_alpha: bool = False, has_content: bool = False, has_news: bool = False,
                             has_notion: bool = False, has_slack: bool = False, has_sheets: bool = False,
                             has_stripe: bool = False,
                             caps_labels: list[str] | None = None,
                             python_code: str | None = None) -> list[tuple[float, str, str]]:
    """Р Р°РЅР¶РёСЂСѓРµС‚ РёРЅС‚РµРіСЂР°С†РёРё РїРѕ СЂРµР»РµРІР°РЅС‚РЅРѕСЃС‚Рё С†РµР»Рё.
    РСЃРїРѕР»СЊР·СѓРµС‚ _rank_goal_capabilities + keyword-boost РґР»СЏ РґРёС„С„РµСЂРµРЅС†РёР°С†РёРё СЃРєРѕСЂРѕРІ."""
    t = goal_title.lower()

    # РљРѕРјРїР°РєС‚РЅР°СЏ С‚Р°Р±Р»РёС†Р°: category в†’ (keywords_hi, keywords_lo)
    # hi = +3 Р·Р° СЃРѕРІРїР°РґРµРЅРёРµ, lo = +1
    _KW_BOOST: dict[str, tuple[tuple, tuple]] = {
        'git':       (('СЂР°Р·СЂР°Р±РѕС‚С‡РёРє', 'РїСЂРѕРіСЂР°РјРјРёСЃС‚', 'developer', 'github', 'С‚РµСЃС‚РёСЂРѕРІС‰РёРє', 'РїРѕР»СЊР·РѕРІР°С‚РµР»',
                       'beta', 'Р±РµС‚Р°', 'СѓС‡Р°СЃС‚РЅРёРє', 'РєР°РЅРґРёРґР°С‚', 'contributor'), ('РєРѕРЅС‚СЂРёР±СЊСЋС‚', 'СЂРµРїРѕР·РёС‚РѕСЂ', 'code', 'recruit')),
        'email':     (('РєР»РёРµРЅС‚', 'РїР°СЂС‚РЅС‘СЂ', 'РїРѕРґРїРёСЃС‡РёРє', 'СЂР°СЃСЃС‹Р»Рє', 'Р°СѓРґРёС‚РѕСЂ', 'РїРѕРєСѓРїР°С‚РµР»', 'Р»РёРґ', 'lead',
                       'outreach', 'email', 'РїРѕС‡С‚'), ()),
        'finance':   (('РЅРµС„С‚', 'РіР°Р·', 'Р°РєС†', 'Р±РёСЂР¶Р°', 'РєРѕС‚РёСЂРѕРІРє', 'oil', 'stock'), ('РёРЅРІРµСЃС‚', 'С‚СЂРµР№Рґ', 'С„РёРЅР°РЅСЃ', 'РІР°Р»СЋС‚')),
        'rss':       (('РЅРѕРІРѕСЃС‚', 'РјРѕРЅРёС‚РѕСЂРёРЅРі', 'С‚СЂРµРЅРґС‹', 'РјРµРґРёР°', 'СЃРјРё', 'Р»РµРЅС‚'), ('Р±Р»РѕРі', 'РѕР±Р·РѕСЂ', 'С„РёРґ')),
        'telegram':  (('РєР°РЅР°Р»', 'Р°СѓРґРёС‚РѕСЂРёСЏ', 'РїРѕРґРїРёСЃС‡РёРє', 'РїРѕСЃС‚', 'smm', 'telegram', 'РєРѕРЅС‚РµРЅС‚'), ('РѕС…РІР°С‚', 'С‚СЂР°С„РёРє')),
        'discord':   (('discord',), ()),
        'notion':    (('Р±Р°Р·Р° Р·РЅР°РЅРёР№', 'РґРѕРєСѓРјРµРЅС‚', 'notion', 'РІРёРєРё'), ('Р·Р°РјРµС‚Рє',)),
        'slack':     (('РєРѕРјР°РЅРґ', 'РєРѕРјРјСѓРЅРёРєР°С†', 'slack'), ('СѓРІРµРґРѕРјР»РµРЅ',)),
        'sheets':    (('С‚Р°Р±Р»РёС†', 'РґР°РЅРЅС‹Рµ', 'Р°РЅР°Р»РёС‚РёРє', 'sheets'), ('РјРµС‚СЂРёРє', 'РѕС‚С‡С‘С‚')),
        'payments':  (('РїР»Р°С‚С‘Р¶', 'РІС‹СЂСѓС‡Рє', 'revenue', 'РѕРїР»Р°С‚', 'stripe'), ('С‚СЂР°РЅР·Р°РєС†',)),
        'crm':       (('crm', 'amocrm', 'Р±РёС‚СЂРёРєСЃ', 'РєР»РёРµРЅС‚', 'СЃРґРµР»Рє', 'Р»РёРґ'), ('РєРѕРЅС‚Р°РєС‚',)),
        'marketplace': (('wildberries', 'ozon', 'Р°РІРёС‚Рѕ', 'РјР°СЂРєРµС‚РїР»РµР№СЃ', 'РїСЂРѕРґР°Р¶'), ('С‚РѕРІР°СЂ', 'СЃРєР»Р°Рґ')),
        'crypto':    (('РєСЂРёРїС‚', 'binance', 'bybit', 'Р±РёС‚РєРѕРёРЅ', 'bitcoin'), ('РјРѕРЅРµС‚', 'С‚РѕРєРµРЅ')),
        'hr':        (('РІР°РєР°РЅСЃРёСЏ', 'СЂРµРєСЂСѓС‚РёРЅРі', 'РЅР°Р№Рј', 'РєР°РЅРґРёРґР°С‚', 'hh.ru', 'headhunter'), ('СЂРµР·СЋРјРµ',)),
        'pm':        (('РїСЂРѕРµРєС‚', 'Р·Р°РґР°С‡', 'jira', 'trello', 'asana'), ('СЃРїСЂРёРЅС‚', 'РєР°РЅР±Р°РЅ')),
        'calendar':  (('РІСЃС‚СЂРµС‡', 'РєР°Р»РµРЅРґР°СЂ', 'СЂР°СЃРїРёСЃР°РЅ', 'zoom'), ('СЃРѕР±С‹С‚',)),
        'calls':     (('Р·РІРѕРЅРє', 'РѕР±Р·РІРѕРЅ', 'sms', 'twilio'), ('С‚РµР»РµС„РѕРЅ',)),
        'social':    (('linkedin', 'instagram', 'twitter', 'РІРєРѕРЅС‚Р°РєС‚', 'СЃРѕС†СЃРµС‚'), ('РїСЂРѕС„РёР»СЊ',)),
        'image_gen': (('РёР·РѕР±СЂР°Р¶РµРЅ', 'РєР°СЂС‚РёРЅРє', 'РіРµРЅРµСЂР°С†', 'replicate'), ('РІРёР·СѓР°Р»',)),
    }

    # РџРѕР»СѓС‡Р°РµРј РєР°С‚РµРіРѕСЂРёРё Р°РіРµРЅС‚Р°
    caps = _classify_agent_caps(caps_labels or [])
    agent_cats = caps.get('categories', set())

    # РЎРєРѕСЂРјРёРј keyword boost
    boost: dict[str, float] = {}
    for cat in agent_cats:
        if cat in _KW_BOOST:
            hi, lo = _KW_BOOST[cat]
            score = sum(3.0 for w in hi if w in t) + sum(1.0 for w in lo if w in t)
            if score > 0:
                boost[cat] = score

    # Р‘Р°Р·РѕРІС‹Рµ СЂРµР·СѓР»СЊС‚Р°С‚С‹ РёР· _rank_goal_capabilities
    result = []
    for base_score, name, route, key in _rank_goal_capabilities(goal_title, caps_labels or [], python_code=python_code):
        if key == 'custom_actions' and not python_code:
            continue
        total = base_score + boost.get(key, 0)
        result.append((total, name, route))

    result.sort(key=lambda x: -x[0])
    return result


# в”Ђв”Ђ РўР°РєС‚РёС‡РµСЃРєРёРµ СЃРµРјРµР№СЃС‚РІР° РёРЅСЃС‚СЂСѓРјРµРЅС‚РѕРІ в”Ђв”Ђ
# РљР°Р¶РґРѕРµ СЃРµРјРµР№СЃС‚РІРѕ = РѕРґРЅР° РєРѕРЅС†РµРїС‚СѓР°Р»СЊРЅР°СЏ СЃС‚СЂР°С‚РµРіРёСЏ. РСЃРїРѕР»СЊР·РѕРІР°Р» РёРЅСЃС‚СЂСѓРјРµРЅС‚ в†’ СЃРµРјРµР№СЃС‚РІРѕ РѕС‚РјРµС‡РµРЅРѕ.
