                    _needs_help = any('РќРЈР–РќР« РљРћРќРўРђРљРўР«' in d for d in _camp_directives)
                    _header = "\n\nрџљЁ РђРљРўРР’РќР«Р• EMAIL-РљРђРњРџРђРќРР (Р’Р«РЎРЁРР™ РџР РРћР РРўР•Рў вЂ” РІС‹РїРѕР»РЅРё РџР•Р Р’Р«Рњ!):\n" if _needs_help else "\n\nрџ“§ РђРљРўРР’РќР«Р• EMAIL-РљРђРњРџРђРќРР:\n"
