    # в”Ђв”Ђ РЎРІРµР¶РёРµ РґР°РЅРЅС‹Рµ РёРЅС‚РµРіСЂР°С†РёР№ (РњРµС‚СЂРёРєР°, GitHub, RSS Рё С‚.Рґ.) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
    _integ_data_block = ''
