            # РСЃРєР»СЋС‡Р°РµРј РёР· "РЅРµ РїРёСЃР°С‚СЊ" С‚РµС… РєС‚Рѕ СѓР¶Рµ РІ РїРµСЂРµРіРѕРІРѕСЂР°С… вЂ” РёРј РЅСѓР¶РµРЅ РѕС‚РІРµС‚
            _already_sent_str_ctx_filtered = [e for e in _already_sent_str_ctx if e.lower() not in _negotiation_ctx]
