            # в•ђв•ђ РљРѕРЅС‚РµРєСЃС‚ РёРЅС‚РµРіСЂР°С†РёР№ РґР»СЏ Р°РіРµРЅС‚Р° в•ђв•ђ
            import os as _os_intg
