            if agents:
                # в”Ђв”Ђ ROUND-ROBIN РґР»СЏ goal_autopilot_review: Р°РіРµРЅС‚С‹ С‡РµСЂРµРґСѓСЋС‚СЃСЏ СЃС‚СЂРѕРіРѕ в”Ђв”Ђ
                # AI-РІС‹Р±РѕСЂ РІСЃРµРіРґР° Р¶РјС‘С‚ РЅР° ASI (specialization=goal_management) в†’
                # РєР°СЃС‚РѕРјРЅС‹Рµ Р°РіРµРЅС‚С‹ (РљСЂРёСЃС‚РёРЅР°, РњР°СЂРє) РІС‹РїР°РґР°СЋС‚ РёР· СЂРѕС‚Р°С†РёРё.
                # Р РµС€РµРЅРёРµ: РґР»СЏ autopilot РїСЂРёРЅСѓРґРёС‚РµР»СЊРЅРѕ С‡РµСЂРµРґСѓРµРј Р°РіРµРЅС‚РѕРІ РІ РїРѕСЂСЏРґРєРµ РёС… id,
                # РёСЃРїРѕР»СЊР·СѓСЏ РїРѕСЃР»РµРґРЅРёР№ dispatched-Р°РіРµРЅС‚ РёР· AgentActivityLog РєР°Рє СѓРєР°Р·Р°С‚РµР»СЊ.
                if anchor.anchor_type == 'custom_anchor':
                    # в”Ђв”Ђ CUSTOM ANCHOR: force-select agent from anchor.data в”Ђв”Ђ
                    _ca_target_id = data.get('agent_id')
