                            user_id=user.id,
                            activity_type='goal_autopilot_dispatch',
                            title=f'{agent_name} вЂ” РѕР±Р·РѕСЂ С†РµР»РµР№',
                            content='',
                            target=anchor.source,
                            status='in_progress',
