                if anchor.anchor_type == 'goal_autopilot_review' and _chosen_id != 0:
                    _gl_titles = [g.get('title', '')[:120] for g in data.get('goals', [])[:3]]
                    # Р’РєР»СЋС‡Р°РµРј РѕРїРёСЃР°РЅРёСЏ С†РµР»РµР№ С‡С‚РѕР±С‹ РєРѕРѕСЂРґРёРЅР°С‚РѕСЂ РїРѕРЅРёРјР°Р» РђРЈР”РРўРћР РР® (С‚СЂРµР№РґРµСЂС‹ vs СЂР°Р·СЂР°Р±РѕС‚С‡РёРєРё vs etc.)
                    _gl_with_desc = []
