                    _agent_role = agent_data.get('job_title') or agent_data.get('specialization') or ''
                    # в”Ђв”Ђ РљР°СЂС‚РѕС‡РєР° РІРѕР·РјРѕР¶РЅРѕСЃС‚РµР№ Р°РіРµРЅС‚Р° С‡РµСЂРµР· СѓРЅРёРІРµСЂСЃР°Р»СЊРЅС‹Р№ _classify_agent_caps в”Ђв”Ђ
                    # _detected СѓР¶Рµ РѕР±РѕРіР°С‰С‘РЅ user-level РєР°РЅР°Р»Р°РјРё С‡РµСЂРµР· _enrich_caps_with_user_channels
                    _caps_c = _classify_agent_caps(_detected or [])
                    _cats_c = _caps_c['categories'].copy()

                    # РЎС‚СЂРѕРёРј СЃРїРёСЃРѕРє "РџРѕРґРєР»СЋС‡РµРЅРѕ" РёР· РєР°С‚РµРіРѕСЂРёР№
                    _connected_names = [_CAP_CATEGORY_NAMES.get(c, c) for c in sorted(_cats_c)]
