                    _can_tools_by_cat = []
                    # РР·РІР»РµРєР°РµРј СЂРµР°Р»СЊРЅС‹Рµ action-РёРјРµРЅР° РёР· python_code Р°РіРµРЅС‚Р°
                    _py_actions_coord = _extract_python_actions(agent_data.get('python_code', ''))
