                                # Dev / QA / Open Source
                                (('СЂР°Р·СЂР°Р±РѕС‚', 'developer', 'qa', 'С‚РµСЃС‚РёСЂРѕРІС‰РёРє', 'РїСЂРѕРіСЂР°РјРјРёСЃС‚', 'open-source', 'РєРѕРґ', 'backend', 'frontend', 'РґРµРїР»РѕР№'), 'github', 'GitHub Token вЂ” РґР»СЏ РїРѕРёСЃРєР° СЂР°Р·СЂР°Р±РѕС‚С‡РёРєРѕРІ Рё РїСЂРѕРµРєС‚РѕРІ'),
                                # Content / SMM / PR
                                (('РїРѕРґРїРёСЃС‡РёРє', 'Р°СѓРґРёС‚РѕСЂ', 'РєРѕРЅС‚РµРЅС‚', 'РѕС…РІР°С‚', 'smm', 'Р±СЂРµРЅРґ', 'pr', 'РїСѓР±Р»РёРєР°С†', 'РїРѕСЃС‚', 'Р±Р»РѕРі'), 'telegram', 'Telegram-РєР°РЅР°Р» вЂ” РґР»СЏ РїСѓР±Р»РёРєР°С†РёРё РєРѕРЅС‚РµРЅС‚Р°'),
                                # Community
