                                # Analytics / Monitoring
                                (('Р°РЅР°Р»РёС‚РёРє', 'РјРѕРЅРёС‚РѕСЂРёРЅРі', 'РЅРѕРІРѕСЃС‚Рё', 'С‚СЂРµРЅРґС‹', 'РѕР±Р·РѕСЂ', 'РґР°Р№РґР¶РµСЃС‚', 'СЂС‹РЅРѕРє', 'РєРѕРЅРєСѓСЂРµРЅС‚'), 'rss', 'RSS/NewsAPI вЂ” РґР»СЏ РјРѕРЅРёС‚РѕСЂРёРЅРіР° С‚СЂРµРЅРґРѕРІ'),
                                # CRM / Sales pipeline
                                (('crm', 'РїСЂРѕРґР°Р¶', 'СЃРґРµР»Рє', 'РІРѕСЂРѕРЅРє', 'pipeline', 'Р»РёРґ', 'РєР»РёРµРЅС‚СЃРє'), 'crm', 'CRM (AmoCRM/HubSpot) вЂ” РґР»СЏ СѓРїСЂР°РІР»РµРЅРёСЏ СЃРґРµР»РєР°РјРё'),
