                                # Crypto / Trading
                                (('РєСЂРёРїС‚', 'Р±РёС‚РєРѕРёРЅ', 'С‚РѕСЂРіРѕРІР»', 'Р±РёСЂР¶Р°', 'С‚СЂРµР№РґРёРЅРі', 'binance'), 'binance', 'РљСЂРёРїС‚РѕР±РёСЂР¶Р° (Binance/Bybit) вЂ” РґР»СЏ С‚РѕСЂРіРѕРІР»Рё'),
